export type HostError = string | {
    GuestPanic: {
        panic_msg: string;
    };
} | {
    InvalidPromiseIndex: {
        promise_idx: number;
    };
} | {
    InvalidPromiseResultIndex: {
        result_idx: number;
    };
} | {
    InvalidRegisterId: {
        register_id: number;
    };
} | {
    IteratorWasInvalidated: {
        iterator_index: number;
    };
} | {
    InvalidReceiptIndex: {
        receipt_index: number;
    };
} | {
    InvalidIteratorIndex: {
        iterator_index: number;
    };
} | {
    ProhibitedInView: {
        method_name: string;
    };
} | {
    NumberOfLogsExceeded: {
        limit: number;
    };
} | {
    KeyLengthExceeded: {
        length: number;
        limit: number;
    };
} | {
    ValueLengthExceeded: {
        length: number;
        limit: number;
    };
} | {
    TotalLogLengthExceeded: {
        length: number;
        limit: number;
    };
} | {
    NumberPromisesExceeded: {
        limit: number;
        number_of_promises: number;
    };
} | {
    NumberInputDataDependenciesExceeded: {
        limit: number;
        number_of_input_data_dependencies: number;
    };
} | {
    ReturnedValueLengthExceeded: {
        length: number;
        limit: number;
    };
} | {
    ContractSizeExceeded: {
        limit: number;
        size: number;
    };
} | {
    Deprecated: {
        method_name: string;
    };
} | {
    ECRecoverError: {
        msg: string;
    };
} | {
    AltBn128InvalidInput: {
        msg: string;
    };
} | {
    Ed25519VerifyInvalidInput: {
        msg: string;
    };
};

export type InvalidAccessKeyError = {
    AccessKeyNotFound: {
        account_id: AccountId;
        public_key: PublicKey;
    };
} | {
    ReceiverMismatch: {
        ak_receiver: string;
        tx_receiver: AccountId;
    };
} | {
    MethodNameMismatch: {
        method_name: string;
    };
} | string | {
    NotEnoughAllowance: {
        account_id: AccountId;
        allowance: string;
        cost: string;
        public_key: PublicKey;
    };
};

/**
 * An error happened during TX execution
 */
export type InvalidTxError = {
    InvalidAccessKeyError: InvalidAccessKeyError;
} | {
    InvalidSignerId: {
        signer_id: string;
    };
} | {
    SignerDoesNotExist: {
        signer_id: AccountId;
    };
} | {
    InvalidNonce: {
        ak_nonce: number;
        tx_nonce: number;
    };
} | {
    NonceTooLarge: {
        tx_nonce: number;
        upper_bound: number;
    };
} | {
    InvalidReceiverId: {
        receiver_id: string;
    };
} | string | {
    NotEnoughBalance: {
        balance: string;
        cost: string;
        signer_id: AccountId;
    };
} | {
    LackBalanceForState: {
        /**
         * Required balance to cover the state.
         */
        amount: string;
        signer_id: AccountId;
    };
} | {
    ActionsValidation: ActionsValidationError;
} | {
    TransactionSizeExceeded: {
        limit: number;
        size: number;
    };
} | {
    StorageError: StorageError;
} | {
    ShardCongested: {
        /**
         * A value between 0 (no congestion) and 1 (max congestion).
         */
        congestion_level: number;
        /**
         * The congested shard.
         */
        shard_id: number;
    };
} | {
    ShardStuck: {
        /**
         * The number of blocks since the last included chunk of the shard.
         */
        missed_chunks: number;
        /**
         * The shard that fails making progress.
         */
        shard_id: number;
    };
};

